data class Product(val name: String, val price: Double, val category: String)

fun main() {
    val products = listOf(
        Product("Laptop", 999.99, "Electronics"),
        Product("Phone", 699.99, "Electronics"),
        Product("Book", 29.99, "Education"),
        Product("Pen", 1.99, "Education"),
        Product("Tablet", 499.99, "Electronics"),
        Product("Coffee", 15.99, "Food")
    )

    // 1. Filter under $50
    val cheap = products.filter { it.price < 50 }
    println("Under \$50: $cheap")

    // 2. Map to names
    val names = products.map { it.name }
    println("Names: $names")

    // 3. Group by category
    val byCategory = products.groupBy { it.category }
    println("By category: $byCategory")

    // 4. Partition
    val (cheap2, expensive) = products.partition { it.price <= 50 }
    println("Cheap (≤ \$50): $cheap2")
    println("Expensive (> \$50): $expensive")

    // 5. Most expensive
    val mostExpensive = products.maxByOrNull { it.price }
    println("Most expensive: $mostExpensive")

    // 6. Total
    val total = products.sumOf { it.price }
    println("Total: $$${total}")

    // 7. Distinct categories
    val categories = products.map { it.category }.distinct()
    println("Categories: $categories")

    // 8. Any over $1000
    val hasExpensive = products.any { it.price > 1000 }
    println("Any over \$1000? $hasExpensive")
}
